import { connect } from "react-redux";
import {
  onPostChangecreateActin,
  addPostcreateActin,
} from "../../redux/messegData-reducer";
import Contacts from "./Contacts";
import { useSelector } from "react-redux";
import { useDispatch } from "react-redux";

const ContactsContainere = () => {
  const counter = useSelector((state) => state.m);
  const dispatch = useDispatch();

  console.log(counter);
};

let mapStateToProps = (state) => {
  return {
    messege: state.messeges,
  };
};
let mapDispatchToProps = (dispatch) => {
  return {
    onPost: (text) => {
      dispatch(onPostChangecreateActin(text));
    },
    addPost: () => {
      dispatch(addPostcreateActin());
    },
  };
};

const ContactsContainer = connect(
  mapStateToProps,
  mapDispatchToProps
)(Contacts);

export default ContactsContainer;
